import{_ as o,o as i,c as t,ag as a}from"./chunks/framework.BvJpShDq.js";const h=JSON.parse('{"title":"Compatibility","titleTemplate":"Simple Voice Chat","description":"","frontmatter":{"titleTemplate":"Simple Voice Chat"},"headers":[],"relativePath":"minecraft/voicechat/wiki/compatibility.md","filePath":"minecraft/voicechat/wiki/compatibility.md"}'),r={name:"minecraft/voicechat/wiki/compatibility.md"};function n(s,e,l,c,d,m){return i(),t("div",null,e[0]||(e[0]=[a('<h1 id="compatibility" tabindex="-1">Compatibility <a class="header-anchor" href="#compatibility" aria-label="Permalink to &quot;Compatibility&quot;">​</a></h1><h2 id="compatibility-between-mod-plugin-versions" tabindex="-1">Compatibility between mod/plugin versions <a class="header-anchor" href="#compatibility-between-mod-plugin-versions" aria-label="Permalink to &quot;Compatibility between mod/plugin versions&quot;">​</a></h2><p>Generally it is always recommended that you use the exact same version on the server and client for the best possible experience.</p><p>This mod follows <a href="https://semver.org/" target="_blank" rel="noreferrer">Semantic Versioning</a>. This means version <code>1.2.3</code> has a major version of <code>1</code>, a minor version of <code>2</code> and a patch version of <code>3</code>. So, as a rule of thumb, <strong>only the major and minor versions need to match</strong>.</p><p>So if your server has version <code>1.2.3</code> of the mod/plugin, your client could also use version <code>1.2.0</code> or <code>1.2.5</code> to join the server and use the mod.</p><h2 id="compatibility-between-minecraft-versions" tabindex="-1">Compatibility between Minecraft versions <a class="header-anchor" href="#compatibility-between-minecraft-versions" aria-label="Permalink to &quot;Compatibility between Minecraft versions&quot;">​</a></h2><p>Simple Voice Chat is compatible between Minecraft versions with the help of tools like <a href="https://modrinth.com/plugin/viaversion" target="_blank" rel="noreferrer">ViaVersion</a>, <a href="https://modrinth.com/plugin/viabackwards" target="_blank" rel="noreferrer">ViaBackwards</a>, <a href="https://modrinth.com/mod/viafabric" target="_blank" rel="noreferrer">ViaFabric</a> or <a href="https://modrinth.com/mod/multiconnect" target="_blank" rel="noreferrer">multiconnect</a>. Note that you still have to consider the compatibility between the mod versions, as described above.</p><h2 id="compatibility-between-mod-plugin-loaders" tabindex="-1">Compatibility between mod/plugin loaders <a class="header-anchor" href="#compatibility-between-mod-plugin-loaders" aria-label="Permalink to &quot;Compatibility between mod/plugin loaders&quot;">​</a></h2><div class="danger custom-block"><p class="custom-block-title">NOTE</p><p>We don&#39;t support <strong>hybrid servers</strong>! Please either use only plugins or only mods on your server. Examples of hybrid servers are <strong>Mohist</strong>, <strong>Arclight</strong>, <strong>Magma</strong> or <strong>Cardboard</strong>. More information about that topic <a href="https://essentialsx.net/do-not-use-mohist.html" target="_blank" rel="noreferrer">here</a>.</p></div><div class="warning custom-block"><p class="custom-block-title">NOTE</p><p>Due to limitations of Forge/NeoForge, clients using <strong>NeoForge</strong> can&#39;t connect to <strong>Forge</strong> servers.</p></div><p>Simple Voice Chat is available for Fabric, NeoForge, Forge, Quilt and Bukkit/Spigot/Paper. All these versions are cross compatible with each other, considering the above limitations.</p><h2 id="operating-system-compatibility" tabindex="-1">Operating system compatibility <a class="header-anchor" href="#operating-system-compatibility" aria-label="Permalink to &quot;Operating system compatibility&quot;">​</a></h2><h3 id="windows" tabindex="-1">Windows <a class="header-anchor" href="#windows" aria-label="Permalink to &quot;Windows&quot;">​</a></h3><p>There are no known incompatibilities with any modern version of Windows (Windows 10 or later).</p><h3 id="macos" tabindex="-1">MacOS <a class="header-anchor" href="#macos" aria-label="Permalink to &quot;MacOS&quot;">​</a></h3><p>MacOS version <code>11</code> or later is required to run Simple Voice Chat on a Mac. Both Intel and ARM based Macs are supported.</p><h3 id="linux" tabindex="-1">Linux <a class="header-anchor" href="#linux" aria-label="Permalink to &quot;Linux&quot;">​</a></h3><p>Simple Voice Chat is compatible with all major Linux distributions, provided they are kept up to date. If you encounter any incompatibility on Linux, please let us know.</p><p>The only additional requirement beyond Minecraft&#39;s usual dependencies is <code>glibc</code> version <code>2.33</code> or newer.</p>',19)]))}const b=o(r,[["render",n]]);export{h as __pageData,b as default};
